const event = $json;
const summary = (event.summary || '').trim();
const description = (event.description || '').trim();
const location = (event.location || '').trim();
const startInfo = event.start || {};
const days = ['일', '월', '화', '수', '목', '금', '토'];

function pad(value) {
  return String(value).padStart(2, '0');
}

function formatLabel(date, includeTime) {
  const base = `${date.getFullYear()}년 ${date.getMonth() + 1}월 ${date.getDate()}일(${days[date.getDay()]})`;
  if (!includeTime) return base;
  return `${base} ${pad(date.getHours())}:${pad(date.getMinutes())}`;
}

let dueAt = null;
let dateLabel = '';
if (startInfo.dateTime) {
  const parsed = new Date(startInfo.dateTime);
  dueAt = startInfo.dateTime;
  dateLabel = Number.isNaN(parsed.getTime()) ? startInfo.dateTime : formatLabel(parsed, true);
} else if (startInfo.date) {
  const parsed = new Date(`${startInfo.date}T09:00:00+09:00`);
  dueAt = `${startInfo.date}T09:00:00+09:00`;
  dateLabel = formatLabel(parsed, false);
} else {
  const now = new Date();
  dueAt = `${now.getFullYear()}-${pad(now.getMonth() + 1)}-${pad(now.getDate())}T09:00:00+09:00`;
  dateLabel = formatLabel(now, false);
}

let relatedProject = null;
let title = summary || '제목 없는 일정';
const separatorIndex = summary.indexOf(' - ');
if (separatorIndex !== -1) {
  relatedProject = summary.substring(0, separatorIndex).trim() || null;
  title = summary.substring(separatorIndex + 3).trim() || title;
}

const sourceMessageId = event.id || `${title}:${dueAt}`;
const sourceParts = [summary || title, `@${dateLabel}`];
if (location) sourceParts.push(`#장소 ${location}`);
if (description) sourceParts.push(`#메모 ${description}`);

return [{
  json: {
    title,
    relatedProject,
    dueAt,
    dateLabel,
    sourceMessageId,
    calendarEventId: event.id || null,
    location,
    sourceText: sourceParts.join(' ')
  }
}];
